from abc import ABC, abstractmethod
from pathlib import Path
from typing import Any, Dict

import pandas as pd
from cifutils import CIFParser

from datahub.common import exists
from datahub.datasets import logger


class RowParser(ABC):
    """
    Abstract base class for DataFrame row parsers.
    Receives a DataFrame row (which varies by source) and parses it into a common dictionary.
    """

    required_schema = {
        "example_id": str,  # Unique identifier for the example, generated by `generate_example_id()` during data pre-processing
        "pdb_id": str,  # PDB ID of the example, or whatever unique identifier is used for entries (e.g., if a dataset is not PDB-based)
        "assembly_id": str,  # Assembly ID of the example, if applicable
        "query_pn_unit_iids": list,  # List of query pn_unit IIDs. I.e., for interfaces, this would be the two contacting pn_unit_iids in the interface
        "extra_info": dict,  # Additional dataset-specific information that isn't universal across all parsers
    }

    def parse(self, row: pd.Series) -> dict[str, Any]:
        """Wrapper to parse and validate a DataFrame row."""
        output = self._parse(row)

        # Validate output
        self.validate_output(output)
        return output

    @abstractmethod
    def _parse(self, row: pd.Series) -> Dict[str, Any]:
        """
        Abstract method to be implemented by subclasses for parsing a DataFrame row.

        Args:
            row (pd.Series): DataFrame row to parse.

        Returns:
            Dict[str, Any]: Parsed output dictionary, including required keys.
        """
        pass

    def validate_output(self, output: Dict[str, Any]) -> None:
        """Validate the output dictionary for required keys and their types."""
        for key in self.required_schema.keys():
            if key not in output:
                if key == "extra_info":
                    output[key] = {}  # Default to an empty dictionary
                else:
                    raise ValueError(f"Missing key in output: {key}")

        extra_keys = output.keys() - self.required_schema.keys()
        if extra_keys:
            raise ValueError(f"Extra keys in output: {extra_keys}")

        for key, expected_type in self.required_schema.items():
            if not isinstance(output[key], expected_type):
                raise TypeError(f"Key '{key}' has incorrect type: expected {expected_type}, got {type(output[key])}")


class PNUnitsDFParser(RowParser):
    """
    Parser for pn_units DataFrame rows.
    """

    def _parse(self, row: pd.Series) -> Dict[str, Any]:
        # For the Query DF, the query pn_unit is the only pn_unit in the query
        query_pn_unit_iids = [row["q_pn_unit_iid"]]

        # Put the full row in the extra info dictionary
        extra_info = row.to_dict()

        return {
            "example_id": row["example_id"],
            "pdb_id": row["pdb_id"],
            "assembly_id": row["assembly_id"],
            "query_pn_unit_iids": query_pn_unit_iids,
            "extra_info": extra_info,
        }


class InterfacesDFParser(RowParser):
    """
    Parser for interfaces DataFrame rows.
    """

    def _parse(self, row: pd.Series) -> Dict[str, Any]:
        # For the Interfaces DF, there are two query pn_units
        query_pn_unit_iids = [row["pn_unit_1_iid"], row["pn_unit_2_iid"]]

        # Put the full row in the extra info dictionary
        extra_info = row.to_dict()

        return {
            "example_id": row["example_id"],
            "pdb_id": row["pdb_id"],
            "assembly_id": row["assembly_id"],
            "query_pn_unit_iids": query_pn_unit_iids,
            "extra_info": extra_info,
        }


def load_from_row(
    # CIFParser `parse` kwargs
    row: pd.Series,
    row_parser: RowParser,
    cif_parser: CIFParser | None = None,
    base_pdb_dir: Path = Path("/databases/rcsb/cif"),
    file_extension: str = ".cif.gz",
    *,
    # CIFParser `parse_from_cif` kwargs
    add_bonds: bool = True,
    add_missing_atoms: bool = True,
    remove_waters: bool = True,
    patch_symmetry_centers: bool = True,
    convert_mse_to_met: bool = True,
    fix_arginines: bool = True,
    keep_hydrogens: bool = False,
    model: int | None = None,  # all models
    cache_dir: Path | None = None,
) -> dict:
    """
    Load data from a DataFrame row into a common format using a given parsing function.

    Args:
        row (pd.Series): DataFrame row to parse.
        parsing_function (RowParser): Parsing function to use. Must be defined in `dataframe_parsers.py`.
        base_pdb_dir (Path): Base directory for PDB files.
        file_extension (str): File extension for PDB files. E.g., ".cif.gz", ".pdb", or ".bcif"

    Returns:
        dict: Parsed and validated output dictionary, standardized across dataframes.
    """
    # Load common outputs from the dataframe using the provided parsing function
    # See `dataframe_parsers.py` for the expected output schema
    parsed_row = row_parser.parse(row)

    # Load the PDB example
    pdb_id = parsed_row["pdb_id"]
    path = Path(f"{base_pdb_dir}/{pdb_id[1:3]}/{pdb_id}{file_extension}")

    if cif_parser is None:
        logger.warning("No parser provided. Initializing default parser; this may take a few seconds.")
        cif_parser = CIFParser()

    # Use the cached parse function
    result_dict = cif_parser.parse(
        filename=str(path),
        build_assembly=(parsed_row["assembly_id"],),  # Convert list to tuple (make hashable)
        add_bonds=add_bonds,
        add_missing_atoms=add_missing_atoms,
        remove_waters=remove_waters,
        patch_symmetry_centers=patch_symmetry_centers,
        convert_mse_to_met=convert_mse_to_met,
        fix_arginines=fix_arginines,
        keep_hydrogens=keep_hydrogens,
        model=model,
        load_from_cache=exists(cache_dir),
        save_to_cache=exists(cache_dir),
        cache_dir=cache_dir,
    )

    # Combine the PDB output and the parsed output into our clean representation
    data = {
        # From the data frame
        "example_id": parsed_row[
            "example_id"
        ],  # Unique identifier for the example, generated by `generate_example_id()
        "pdb_id": pdb_id,
        "assembly_id": parsed_row["assembly_id"],
        "query_pn_unit_iids": parsed_row[
            "query_pn_unit_iids"
        ],  # List of polymer/non-polymer unit instance IDs, e.g., length two for an interface, length one for an individual pn_unit
        "extra_info": parsed_row["extra_info"],
        # From the parser
        "atom_array": result_dict["assemblies"][parsed_row["assembly_id"]][0],  # First model
        "atom_array_stack": result_dict["assemblies"][parsed_row["assembly_id"]],  # All models
        "chain_info": result_dict["chain_info"],
        "ligand_info": result_dict["ligand_info"],
        "metadata": result_dict["metadata"],
    }

    return data
